ck</span>(<span class=\"dc\">sku</span>):\n      <span class=\"kw\">raise</span> <span class=\"cl\">ValueError</span>(<span class=\"st\">\"Out of stock\"</span>)\n    <span class=\"dc\">self._pay</span>.<span class=\"fn\">charge</span>(<span class=\"dc\">price</span>)\n    <span class=\"kw\">return</span> <span class=\"dc\">self._shp</span>.<span class=\"fn\">ship</span>(<span class=\"dc\">sku</span>)\n\n<span class=\"cm\"># tracking = OrderFacade().place_order(\"SKU-001\", 99.90)</span>", "Ruby": "<span class=\"kw\">class</span> <span class=\"cl\">OrderFacade</span>\n  <span class=\"kw\">def</span> <span class=\"fn\">initialize</span>\n    <span class=\"dc\">@inv</span>, <span class=\"dc\">@pay</span>, <span class=\"dc\">@shp</span> =\n      <span class=\"cl\">Inventory</span>.<span class=\"fn\">new</span>, <span class=\"cl\">Payment</span>.<span class=\"fn\">new</span>, <span class=\"cl\">Shipping</span>.<span class=\"fn\">new</span>\n  <span class=\"kw\">end</span>\n\n  <span class=\"kw\">def</span> <span class=\"fn\">place_order</span>(<span class=\"dc\">sku</span>, <span class=\"dc\">price</span>)\n    <span class=\"kw\">raise</span> <span class=\"st\">\"Out of stock\"</span> <span class=\"kw\">unless</span> <span class=\"dc\">@inv</span>.<span class=\"fn\">check</span>(<span class=\"dc\">sku</span>)\n    <span class=\"dc\">@pay</span>.<span class=\"fn\">charge</span>(<span class=\"dc\">price</span>)\n    <span class=\"dc\">@shp</span>.<span class=\"fn\">ship</span>(<span class=\"dc\">sku</span>)\n  <span class=\"kw\">end</span>\n<span class=\"kw\">end</span>"}

